1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PREMIUM = 60;
4	const CURSED_SURCHARGE_RATE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
11	
12	const BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	function calculateItemPremium(item: any): number {
24	  const basePremium = BASE_PREMIUM[item.type] ?? 0;
25	  const cursedSurcharge = item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0;
26	  const enchantmentSurcharge = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
27	  return basePremium + cursedSurcharge + enchantmentSurcharge;
28	}
29	
30	function computePremiumBreakdown(items: any[]): { itemPremiums: number; policyBase: number } {
31	  const componentCounts: Record<string, number> = {};
32	  let itemPremiums = 0;
33	  let policyBase = 0;
34	
35	  for (const item of items) {
36	    if (COMPONENT_TYPES.has(item.type)) {
37	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
38	    } else {
39	      if (!(item.type in BASE_PREMIUM)) {
40	        throw new Error(`Unknown item type: ${item.type}`);
41	      }
42	      const basePremium = BASE_PREMIUM[item.type] ?? 0;
43	      policyBase += basePremium;
44	      itemPremiums += calculateItemPremium(item);
45	    }
46	  }
47	
48	  for (const [type, count] of Object.entries(componentCounts)) {
49	    const unitPrice = BASE_PREMIUM[type] ?? 0;
50	    const componentPremium = count === BLOCK_SIZE ? BLOCK_PREMIUM : count * unitPrice;
51	    itemPremiums += componentPremium;
52	    policyBase += count * unitPrice;
53	  }
54	
55	  return { itemPremiums, policyBase };
56	}
57	
58	export function processScenario(scenario: any): unknown {
59	  const results = scenario.steps.map((step: any, index: number) => {
60	    const { itemPremiums, policyBase } = computePremiumBreakdown(step.items);
61	    const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
62	    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
63	    const followUpDiscount = index > 0 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
64	    const premium = Math.ceil(itemPremiums + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
65	    return { premium };
66	  });
67	  return { results };
68	}
